/* ==================================
   re-section.js - Monthly Retrospective Section
   ⚠️ 이 파일은 manager.py가 자동 생성합니다
   ================================== */

const isLocal = window.location.protocol === 'file:';

// Re section data - Generated by manager.py
const reData = [{"month": "2026.04", "url": "#", "title": "건네받은 삼월의 나날들, 사월이라는 이름표와 넥스트 러너로서 달려나가며", "title_en": "Passing over the days of March, with a name tag called April, running as a Next Runner", "content_file": "2026_04_Resolve.json", "type": "Resolve"}, {"month": "2026.03", "url": "#", "title": "궤도에 Merge 시킨 나날들을 사월의 동력으로 건네며", "title_en": "Passing the Days Merged into Orbit as Fuel for April", "content_file": "2026_03_Retrospect.json", "type": "Retrospect"}, {"month": "2026.03", "url": "#", "title": "3월을 궤도에 Merge 시키며", "title_en": "Merging March into Orbit", "content_file": "2026_03_Resolve.json", "type": "Resolve"}, {"month": "2026.02", "url": "#", "title": "2월을 26시키며.", "title_en": "Landing February 2026.", "content_file": "2026_02_Retrospect.json", "type": "Retrospect"}, {"month": "2026.02", "url": "#", "title": "1월의 노력을 2월에 이월하며 :)", "title_en": "Carrying Over January's Efforts into February :)", "content_file": "2026_02_Resolve.json", "type": "Resolve"}, {"month": "2026.01", "url": "#", "title": "2026년 1월을 떠나보내며.", "title_en": "Farewell to January 2026.", "content_file": "2026_01_Retrospect.json", "type": "Retrospect"}, {"month": "2026.01", "url": "#", "title": "2026년을 맞이하며 (Welcoming 2026)", "title_en": "Welcoming 2026", "content_file": "2026_01_Resolve.json", "type": "Resolve"}];

let activeFilter = 'all';

function generateReCards() {
    const grid = document.getElementById('reGrid');
    const lang = typeof currentLang !== 'undefined' ? currentLang : 'KR';
    
    const filteredData = activeFilter === 'all' 
        ? reData 
        : reData.filter(item => item.month.startsWith(activeFilter));

    grid.innerHTML = filteredData.map((item, idx) => `
        <div class="re-card" onclick="openReModal(${idx})" data-idx="${idx}">
            <div class="re-month">${item.month}</div>
            <div class="re-title">${lang === 'KR' ? item.title : (item.title_en || item.title)}</div>
            <div class="re-status">${lang === 'KR' ? '클릭하여 읽기' : 'Click to read'}</div>
        </div>
    `).join('');
    
    updateFilterOptions();
}

function updateFilterOptions() {
    const filter = document.getElementById('reYearFilter');
    if (!filter) return;
    
    const years = [...new Set(reData.map(item => item.month.split('.')[0]))].sort().reverse();
    const currentOptions = Array.from(filter.options).map(opt => opt.value);
    
    years.forEach(year => {
        if (!currentOptions.includes(year)) {
            const option = document.createElement('option');
            option.value = year;
            option.textContent = year + ' Year';
            filter.appendChild(option);
        }
    });
}

function filterReCards() {
    const filter = document.getElementById('reYearFilter');
    activeFilter = filter.value;
    generateReCards();
}

function openReModal(idx) {
    const lang = typeof currentLang !== 'undefined' ? currentLang : 'KR';
    const item = activeFilter === 'all' ? reData[idx] : reData.filter(d => d.month.startsWith(activeFilter))[idx];
    
    if (!item) return;

    const overlay = document.getElementById('reModalOverlay');
    const contentArea = document.getElementById('reModalContent');
    const titleText = lang === 'KR' ? item.title : (item.title_en || item.title);
    
    // Show loading state
    contentArea.innerHTML = `
        <div class="re-modal-month">${item.month}</div>
        <h2 class="re-modal-title">${titleText}</h2>
        <div class="re-modal-body" style="text-align: center; padding: 40px 0;">
            <div class="loading-spinner">Loading...</div>
        </div>
    `;
    
    overlay.classList.add('show');
    document.body.style.overflow = 'hidden';

    // Fetch the content
    const contentPath = 'assets/re_data/' + item.content_file;
    
    fetch(contentPath)
        .then(response => {
            if (!response.ok) throw new Error('File not found');
            return response.json();
        })
        .then(data => {
            const textContent = lang === 'KR' ? (data.desc_kr || data.desc) : (data.desc_en || data.desc || data.desc_kr);
            
            contentArea.innerHTML = `
                <div class="re-modal-month">${item.month}</div>
                <h2 class="re-modal-title">${titleText}</h2>
                <div class="re-modal-body">
                    ${textContent}
                </div>
                ${(!isLocal && item.url && item.url !== '#') ? `<a href="${item.url}" target="_blank" class="re-link" style="margin-top: 40px; display: inline-block;">Read full review →</a>` : ''}
            `;

            // Re-render MathJax inside the modal
            if (typeof MathJax !== 'undefined' && MathJax.typesetPromise) {
                MathJax.typesetPromise([contentArea]).catch(err => console.log('MathJax:', err));
            }
        })
        .catch(err => {
            console.error('Error loading review:', err);
            contentArea.innerHTML = `
                <div class="re-modal-month">${item.month}</div>
                <h2 class="re-modal-title">${titleText}</h2>
                <div class="re-modal-body" style="color: #ff6b6b; text-align: center;">
                    ${lang === 'KR' ? '내용을 불러올 수 없습니다.' : 'Failed to load content.'}
                </div>
            `;
        });
}

function closeReModal(event) {
    const overlay = document.getElementById('reModalOverlay');
    overlay.classList.remove('show');
    document.body.style.overflow = 'auto'; // Restore background scrolling
}

// Add Escape key listener to close modal
document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
        const overlay = document.getElementById('reModalOverlay');
        if (overlay && overlay.classList.contains('show')) {
            closeReModal();
        }
    }
});
